@Composable
fun CardListScreen() {
    val cards = remember { listOf(
        Card("1", "Kotlin"), Card("2", "Compose"), Card("3", "Room")
    )}
    var selectedIds by remember { mutableStateOf(setOf<String>()) }

    LazyColumn {
        items(cards, key = { it.id }) { card ->
            CardItem(
                card = card,
                isSelected = card.id in selectedIds,
                onClick = {
                    selectedIds = if (card.id in selectedIds)
                        selectedIds - card.id
                    else
                        selectedIds + card.id
                }
            )
        }
    }
}

