@Stable
class CardState(val card: Card) {
    var isSelected by mutableStateOf(false)
        private set
    var isExpanded by mutableStateOf(false)
        private set

    fun toggleSelected() { isSelected = !isSelected }
    fun toggleExpanded() { isExpanded = !isExpanded }
}

@Composable
fun SmartCardItem(state: CardState) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .clickable { state.toggleSelected() }
            .background(if (state.isSelected) Color.Blue.copy(alpha = 0.1f) else Color.Transparent)
    ) {
        Text(state.card.title)
        if (state.isExpanded) {
            Text(state.card.description)
        }
    }
}

