@Stable
class TodoItemState(
    val id: String,
    val title: String,
    isCompleted: Boolean = false,
    note: String = ""
) {
    var isCompleted by mutableStateOf(isCompleted)
        private set
    var isExpanded by mutableStateOf(false)
        private set
    var note by mutableStateOf(note)

    fun toggleCompleted() { isCompleted = !isCompleted }
    fun toggleExpanded() { isExpanded = !isExpanded }
}

@Composable
fun TodoItem(state: TodoItemState) {
    Column(modifier = Modifier.fillMaxWidth().padding(12.dp)) {
        Row(verticalAlignment = Alignment.CenterVertically) {
            Checkbox(
                checked = state.isCompleted,
                onCheckedChange = { state.toggleCompleted() }
            )
            Text(
                text = state.title,
                textDecoration = if (state.isCompleted)
                    TextDecoration.LineThrough else TextDecoration.None,
                modifier = Modifier.weight(1f)
            )
            IconButton(onClick = { state.toggleExpanded() }) {
                Icon(
                    if (state.isExpanded) Icons.Default.ExpandLess
                    else Icons.Default.ExpandMore,
                    contentDescription = "Expand"
                )
            }
        }
        AnimatedVisibility(visible = state.isExpanded) {
            TextField(
                value = state.note,
                onValueChange = { state.note = it },
                label = { Text("Note") },
                modifier = Modifier.fillMaxWidth().padding(top = 8.dp)
            )
        }
    }
}

