// Move CardState management into the ViewModel
class CardViewModel : ViewModel() {
    private val _cardStates = MutableStateFlow<List<CardState>>(emptyList())
    val cardStates: StateFlow<List<CardState>> = _cardStates.asStateFlow()

    init {
        viewModelScope.launch {
            val cards = repository.getCards()
            _cardStates.value = cards.map { CardState(it.id, it.title) }
        }
    }
}

